### 📋 任务详情

#### 1️⃣ 创建 WebSocket 服务封装

创建文件：`dashboard/src/services/websocket.ts`

```typescript
export class DashboardWebSocket {
  private ws: WebSocket | null = null
  private reconnectTimer: any = null
  private messageHandlers: Map<string, Function[]> = new Map()

  connect(url: string) {
    this.ws = new WebSocket(url)

    this.ws.onopen = () => {
      console.log('✅ WebSocket 已连接')
    }

    this.ws.onmessage = (event) => {
      try {
        const { event: type, data } = JSON.parse(event.data)
        this.emit(type, data)
      } catch (error) {
        console.error('解析消息失败:', error)
      }
    }

    this.ws.onerror = (error) => {
      console.error('WebSocket 错误:', error)
    }

    this.ws.onclose = () => {
      console.log('🔌 WebSocket 已断开，5秒后重连...')
      this.reconnectTimer = setTimeout(() => {
        this.connect(url)
      }, 5000)
    }
  }

  on(event: string, handler: Function) {
    if (!this.messageHandlers.has(event)) {
      this.messageHandlers.set(event, [])
    }
    this.messageHandlers.get(event)!.push(handler)
  }

  private emit(event: string, data: any) {
    const handlers = this.messageHandlers.get(event) || []
    handlers.forEach(handler => handler(data))
  }

  disconnect() {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer)
    }
    if (this.ws) {
      this.ws.close()
    }
  }
}
```

#### 2️⃣ 创建实时日志查看器组件

创建文件：`dashboard/src/components/LogViewer.vue`

```vue
<template>
  <div class="log-viewer">
    <div class="log-header">
      <h3>📡 实时日志</h3>
      <div class="controls">
        <el-switch 
          v-model="autoScroll" 
          active-text="自动滚动"
          inline-prompt
        />
        <el-button @click="clearLogs" size="small">清空</el-button>
        <el-tag :type="connected ? 'success' : 'danger'">
          {{ connected ? '已连接' : '未连接' }}
        </el-tag>
      </div>
    </div>

    <div class="log-content" ref="logContainer">
      <div 
        v-for="(log, index) in logs" 
        :key="index"
        :class="['log-item', `log-${log.level}`]"
      >
        <span class="log-time">{{ formatTime(log.timestamp) }}</span>
        <span class="log-level">[{{ log.level }}]</span>
        <span class="log-message">{{ log.message }}</span>
      </div>

      <div v-if="logs.length === 0" class="log-empty">
        等待日志数据...
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, onUnmounted, nextTick, watch } from 'vue'
import { DashboardWebSocket } from '@/services/websocket'

const logs = ref<any[]>([])
const connected = ref(false)
const autoScroll = ref(true)
const logContainer = ref<HTMLElement>()

let ws: DashboardWebSocket | null = null

const formatTime = (timestamp: string) => {
  const date = new Date(timestamp)
  return date.toLocaleTimeString('zh-CN', { hour12: false })
}

const addLog = (data: any) => {
  logs.value.push({
    timestamp: data.timestamp || new Date().toISOString(),
    level: data.level || 'INFO',
    message: data.message || JSON.stringify(data)
  })

  // 限制最大日志数量
  if (logs.value.length > 500) {
    logs.value.shift()
  }

  // 自动滚动到底部
  if (autoScroll.value) {
    nextTick(() => {
      if (logContainer.value) {
        logContainer.value.scrollTop = logContainer.value.scrollHeight
      }
    })
  }
}

const clearLogs = () => {
  logs.value = []
}

onMounted(() => {
  ws = new DashboardWebSocket()

  // 连接 WebSocket
  const wsUrl = import.meta.env.VITE_WS_URL || 'ws://localhost:3000/api/ws'
  ws.connect(wsUrl)

  // 监听连接状态
  ws.on('connected', () => {
    connected.value = true
  })

  ws.on('disconnected', () => {
    connected.value = false
  })

  // 监听日志消息
  ws.on('log', addLog)
  ws.on('iteration.status_changed', (data) => {
    addLog({
      level: 'INFO',
      message: `迭代状态变更: ${data.status}`,
      timestamp: new Date().toISOString()
    })
  })
  ws.on('agent.status_changed', (data) => {
    addLog({
      level: 'INFO',
      message: `Agent ${data.agentName}: ${data.status}`,
      timestamp: new Date().toISOString()
    })
  })
})

onUnmounted(() => {
  if (ws) {
    ws.disconnect()
  }
})
</script>

<style scoped>
.log-viewer {
  border: 1px solid var(--el-border-color);
  border-radius: 8px;
